  gradeBoostingVocabulary: [
    { term: 'Bildungsroman', definition: 'A "novel of formation" tracing a protagonist\'s moral and psychological development from childhood to maturity.' },
    { term: 'Byronic hero', definition: 'A brooding, charismatic, morally ambiguous male figure, inspired by the works of Lord Byron. Rochester is a classic Byronic hero.' },
    { term: 'Pathetic fallacy', definition: 'The attribution of human emotions to natural phenomena (e.g., storms reflecting inner turmoil).' },
    { term: 'Gothic', definition: 'A literary mode characterised by mystery, horror, the supernatural, and settings like castles, mansions, and ruins.' },
    { term: 'Free indirect discourse', definition: 'A narrative technique that blends the narrator\'s voice with a character\'s thoughts, without quotation marks or reporting verbs.' },
    { term: 'Foil', definition: 'A character who contrasts with the protagonist, highlighting specific qualities (e.g., St John as a foil to Rochester).' },
    { term: 'Symbolism', definition: 'The use of objects, settings, or events to represent abstract ideas (e.g., the red-room as a symbol of confinement).' },
    { term: 'Motif', definition: 'A recurring element (image, symbol, phrase) that develops a theme throughout the text (e.g., birds, fire, ice).' },
    { term: 'Dramatic irony', definition: 'When the reader knows more than the character (e.g., we suspect Bertha\'s existence before Jane discovers it).' },
    { term: 'Patriarchal', definition: 'Relating to a social system in which men hold primary power and authority. Jane Eyre critiques patriarchal structures.' },
    { term: 'Agency', definition: 'A character\'s capacity to act independently and make their own choices. Jane\'s agency is the novel\'s central concern.' },
    { term: 'Liminal', definition: 'Occupying a threshold or in-between position (e.g., the governess is liminal — neither servant nor family).' },
    { term: 'Doppelgänger / Double', definition: 'A character who mirrors another, often representing repressed qualities (e.g., Bertha as Jane\'s double).' },
    { term: 'Subversion', definition: 'The act of undermining or overturning expectations or conventions (e.g., Jane subverts the passive heroine tradition).' },
    { term: 'Imperative', definition: 'A command form of a verb. Brocklehurst and Mrs Reed frequently use imperatives, reflecting their authoritarian power.' },
    { term: 'Tricolon', definition: 'A rhetorical device using three parallel elements for emphasis (e.g., "solitary... friendless... unsustained").' },
    { term: 'Antithesis', definition: 'The juxtaposition of contrasting ideas (e.g., passion vs. principle, fire vs. ice).' },
    { term: 'Epistolary', definition: 'Relating to letters. Key letters in the novel (Rochester\'s, St John\'s) advance the plot and reveal character.' },
    { term: 'Juxtaposition', definition: 'Placing two elements side by side for comparison or contrast (e.g., Brocklehurst\'s daughters in silk vs. Lowood girls in rags).' },
    { term: 'Retrospective narration', definition: 'A narrative told by an older version of the protagonist looking back on past events, allowing for both immediacy and reflection.' },
  ],

